var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"큭…… 하아……","JPN":"くっ……はあ……","ENG":"*Pant*","TWN":"咳……呼呼……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님, 상처가 너무 심합니다!","JPN":"湊様、傷が深すぎます！","ENG":"Mr. Nayuka, you’re seriously injured!","TWN":"南裕夏，你傷勢很嚴重！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜찮아. 아직 활을 당기는 것쯤은…… 할 수 있어.","JPN":"平気さ。まだ弓を引くことくらい……できる。","ENG":"I’m okay. I can still pull the string.","TWN":"沒關係，還可以拉弓… 我可以的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그런 꼴로도 아직 저항할 수 있다니.","JPN":"そんな様でもまだ抵抗するとは。","ENG":"You still have a plenty of fight in you.","TWN":"都傷成那樣還要抵抗嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"아쉽지만, 목숨을 구걸하는 꼴은 못 보겠구나.","JPN":"残念だが、命乞いをする姿は見られそうにないな。","ENG":"I guess you won’t be begging for your life.","TWN":"雖然很可惜，但你那副可憐樣我實在看不下去。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"지금 당장 사이좋게 저승으로 보내주마.","JPN":"今すぐにまとめてあの世に送ってやろう。","ENG":"Well then, let me send you both to the hell.","TWN":"我現在就立刻送你上路。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……치나츠.","JPN":"……千夏。","ENG":"... Chinatsu.","TWN":"……千夏。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"엎드려!","JPN":"伏せて！","ENG":"Stay down!","TWN":"趴下！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"침식체들이…… 날아갔어?","JPN":"侵食体が……飛ばされた？","ENG":"The C.O.s flew away...","TWN":"侵蝕體……消失了？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"뭐냐? 방금 대체 무슨 일이 일어난 거지?","JPN":"なんだ？　今何が起きた？","ENG":"What? What just happened?","TWN":"什麼？剛才到底發生什麼事？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저건……","JPN":"あれは……","ENG":"That’s...","TWN":"那是……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_COFFIN_START"},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"카미이즈미?","JPN":"上泉？","ENG":"Kamiizumi?","TWN":"上泉？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"한 발 적중! 맛이 어떠냐!","JPN":"一発必中！　ざまあみろ！","ENG":"Bullseye! How did you like that?","TWN":"一發命中！ 滋味如何！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"터뷸런스 동력을 다시 최대로 끌어올리자고!","JPN":"タービュランス動力をもう一度最大まで引き上げようぜ！","ENG":"Let’s maximize the power of Turbulence again!","TWN":"再把不穩定氣流的動能升到最大！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"터뷸런스 엔진은 무기가 아닙니다. 지속적으로 부하시키면 폭발 위험이 있습니다.","JPN":"タービュランス動力は武器ではありません。\\n何度も負荷をかけると爆発の恐れがございます。","ENG":"The Turbulence engine is not a weapon; you can’t repeatedly overload it.","TWN":"不穩定氣流引擎不是武器，繼續加壓會有爆炸危險。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"비행 동력 기관의 모든 냉각기능을 엔진에 집중시키면 돼!","JPN":"飛行動力機関の冷却機能を全部エンジンに集中させればいい！","ENG":"It’ll be okay if we focus the cooling system 100% on the engine!","TWN":"只要把飛行動力機的所有冷卻功能，都集中到引擎上就行啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"추락할 겁니다. 침식체들의 공격범위에 노출될 텐데요.","JPN":"そんなことをしたら墜落してしまいます。\\n侵食体の攻撃範囲に入ると思われますが。","ENG":"We will fall. Then C.O.s will attack us.","TWN":"這樣會墜機，而且會暴露在侵蝕體的攻擊範圍中。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"알아! 지상에 인사하러 가자고!","JPN":"わかってる！　地上に挨拶しに行ってやろうぜ！","ENG":"I know that! Let’s go say hello to the ones on the ground!","TWN":"我知道！去地上打招呼吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"카미이즈미?!","JPN":"上泉！？","ENG":"Kamiizumi?","TWN":"上泉？！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"도대체 저게 왜 여기에 나타난 거냐?","JPN":"どうしてあれがここに……？","ENG":"Why on earth is it here?","TWN":"那東西到底爲什麼出現在這裡？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"……장로!","JPN":"……長老！","ENG":"... Elder!","TWN":"……長老！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L2_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"카토리 놈이 탈출했소! 격납고에 있던 카미이즈미를 빼앗겼어!","JPN":"香取の奴が脱出した！　格納庫にあった上泉を奪われたぞ！","ENG":"Katori escaped! He took Kamiizumi from the hangar!","TWN":"香取逃走了！ 機庫裡的上泉也被搶走了！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그건 알고 있다, 이 아둔한 놈아. 지금 눈앞을 날아다니고 있지 않느냐?","JPN":"それは知っている、この愚か者め。\\n今、目の前を飛び回っているではないか！","ENG":"I know that, you idiot. It’s flying right in front of my eyes!","TWN":"我知道，你這個蠢蛋。不就在我眼前明擺著嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"연합에서 가장 위험한 병기를 그렇게 쉽게 내어 주다니!","JPN":"連合で最も危険な兵器をいとも簡単に盗られるとは！","ENG":"You let them take the most dangerous weapon the Alliance has!","TWN":"聯盟竟然如此輕易就將最危險的兵器給出去！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"대체 경비가 얼마나 허술했던 거야! 내가 죽여도 상관없다고 했을 텐데?","JPN":"警備はいったい何をしていたのだ！　\\n殺しても構わないと言ったはずだが？","ENG":"What were the guardsmen doing? I told you that you could kill them if necessary!","TWN":"戒備到底有多鬆散！我不是說過必要的時候殺無赦嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"……미, 미안하게 됐군.","JPN":"……す、すまない。","ENG":"I-I’m sorry...","TWN":"……對…對不起。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그런데 봉인은 어떻게 됐지?","JPN":"ところで封印はどうなったのだ？","ENG":"What happened to the seal?","TWN":"不過，封印怎麼樣？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나나하라 당주의 피를 뿌리기만 하면 오로치님께서도 깨어나실 거다.","JPN":"あとは七原家当主の血さえ捧げればオロチ様がお目覚めになるだろう。","ENG":"Once we shed Nanahara blood, Lord Orochi will awake.","TWN":"只要撒下七原堂主的血，大蛇應該就會甦醒過來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나나하라 가문의 보검, 천총운검을 통해 흘린 무녀의 피가 아니라면 그 피는 오히려 봉인을 깨는 촉진제가 될 뿐이니까.","JPN":"巫女の血だとしても、七原家の宝剣である天叢雲剣によって流したものでなければ、\\nむしろ封印を破る促進剤になるだけだからな。","ENG":"The priestess’s blood spilled with any weapon other than Kusanagi will only help break the seal.","TWN":"若巫女的血不是藉著七原家族的寶劍 天叢雲劍流出，那血反而會成爲打破封印的促進劑。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"평소엔 호위 무사가 지키고 있어서 곤란했지만, 지금이라면 쉽게 처리할 수 있어.","JPN":"普段は護衛のせいで隙がなかったが、今なら簡単に処理できる。","ENG":"It was difficult when her bodyguard was around, but now we can kill her with ease.","TWN":"平時因為有護衛武士在看守不太容易，但現在可以輕易處理。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"걱정 마시오! 내 병사들이 뒤에서 지원을 오고 있으니……","JPN":"心配はいらぬ！　今わしの兵士たちが加勢に来て……","ENG":"Don’t worry, my soldiers are coming to help you—","TWN":"別擔心！我的士兵正在趕來……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"다, 당주님! 매복입니다!","JPN":"と、当主様！　待ち伏せです！","ENG":"L-Lady, it’s an ambush!","TWN":"堂…堂主！有埋伏！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"뭐? 그게 무슨 소리냐?","JPN":"は？　どういうことだ？","ENG":"Huh? What are you talking about?","TWN":"什麼？那是什麼意思？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"아, 아무래도 정보가 새어 나간 것 같습니다!","JPN":"ど、どうやら情報が漏れていたようです！","ENG":"I-I think they knew our plan!","TWN":"可能…有人洩漏情報！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"말씀하신 대로군요!","JPN":"おっしゃるとおりでしたね！","ENG":"It was as you said!","TWN":"果然跟你說的一樣！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"요즘 몇몇 장로들의 움직임이 심상치 않다 싶었는데, 나나하라 당주의 허가도 없이 이런 대규모 병력을 움직이다니.","JPN":"最近一部の長老たちの動きが怪しいと思っていましたが、\\n七原家当主の許可もなく、こんな大規模な兵力を動かすとは。","ENG":"I knew some Elders were up to something, and now they are secretly mobilizing their army without Lady Nanahara’s permission.","TWN":"最近幾位長老的行爲不太尋常，居然在沒有得到七原堂主許可的情況下，就動用如此大規模的兵力。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 내가 뭐랬어?","JPN":"ふん、オレ様が言ったとおりだろ？","ENG":"Hmpf, I told you!","TWN":"哼，是不是？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"한 놈도 남기지 말고 모두 잡아들여! 후에 흑막조…… 아니, 나나하라 당주님이 처벌하실 거다.","JPN":"一人も残さず全員捕まえろ！\\nあとで黒幕組……いや、七原家当主が処罰するだろう。","ENG":"Arrest them all! Then the Ogami Shadow Group—I mean, Lady Nanahara will pass judgment on them.","TWN":"一個也別想逃，全都給我抓起來！之後交由黑幕組……不對，是交由七原堂主發落。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그리고……","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"날 신용해줘서 고맙다, 제군들.","JPN":"オレを信じてくれて感謝する、諸君。","ENG":"Thank you for trusting me.","TWN":"謝謝各位相信我。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"그런데 생각해보면 우리도 이놈들을 잡겠다고 나나하라 당주님 허가없이 군사를 움직인 게 아닙니까?","JPN":"ところでよく考えてみれば、私たちもこいつらを捕まえるために\\n七原家当主の許可なく軍を動かしたことになりますが。","ENG":"But then again, we acted on our own to arrest these men, without the permission of Lady Nanahara.","TWN":"不過，我們不是也因爲要抓這些傢伙，而在沒有得到堂主許可的情況下出兵嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"처벌 받지 않을까요?","JPN":"処罰を受けるのでは？","ENG":"Maybe we’ll be punished, too.","TWN":"那會受到處罰嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"우리가 하는 일이 징계감이라면 군말없이 받아야지.","JPN":"俺たちのやることが間違っているなら、文句なしに処罰を受けるべきだろ。","ENG":"If we have to be punished, we’ll be punished.","TWN":"如果我們做的事要受罰，就應該乖乖受罰。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"하지만 다른 가문도 아니고 카토리 당주잖나?","JPN":"しかし他でもない香取家当主だぞ？","ENG":"But you know Mr. Katori.","TWN":"可是又不是別的家族，是香取堂主欸？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"그분 아들의 지시였어. 나나하라 당주께서도 현명하게 잘 판단하실 거다.","JPN":"あの方のご子息の指示だ。\\n七原家の当主様もきっと、賢明に判断してくださるだろう。","ENG":"It was his son who requested our help. I believe Lady Nanahara will make a wise decision.","TWN":"是他兒子的指示，七原堂主也會做出明智判斷的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……합을 겨뤄보니 알겠구나.","JPN":"……一戦交えてわかった。","ENG":"Now I see who you are.","TWN":"……試試看就知道。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"선대 당주의 호위무사는 카운터가 아니지만 관리국의 무장을 사용했다고 들었다.","JPN":"先代当主の護衛はカウンターではなかったが、\\n管理局の武装を使っていたと聞いたことがある。","ENG":"I heard the bodyguard of the previous Alliance leader was not a Counter, but she used Administration weapons.","TWN":"先祖堂主的護衛武士雖然不是制裁者，但聽說有使用管理局的武裝。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"실과 바늘.","JPN":"糸と針。","ENG":"Needle and Thread.","TWN":"針跟線。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주를 죽이고 도망쳤다던 당신이…… 아직도 이곳에 있었을 줄이야.","JPN":"当主を殺して逃げたというあなたが……まだここにいたとは。","ENG":"I heard you killed your Lady and ran away... yet you’re still here.","TWN":"殺掉堂主後逃跑的你…… 沒想到還在這裡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"오로치의 독기가 네놈을 잠들지도 못하는 망령으로 만든 건가?","JPN":"オロチの毒が、お前を眠れぬ亡霊にしたのか？","ENG":"Did Orochi’s poison make you a wraith?","TWN":"是大蛇的毒氣把你變成無法沉睡的亡靈嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"……지금이라도 돌아가 목숨을 부지하십시오.","JPN":"……今からでもお引き取りいただき、その命を大事にしてください。","ENG":"... I suggest thou run now, to save thy life.","TWN":"……勸你們還是回去吧，保命要緊。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"운명에 저항해봤자, 바뀌는 것은 없으니…… 명을 재촉할 뿐이랍니다.","JPN":"運命に抵抗しても何も変わらない……\\n自らの寿命を縮めるだけでございまする。","ENG":"Do not try to fight fate. Nothing will change, and thou wilt only lose thy life.","TWN":"反抗命運也不會改變任何東西…只會加速滅亡而已。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"같은 말 밖에 반복할 줄 몰라서야, 인형과 다를 바 없구나.","JPN":"同じ言葉しか繰り返すことができないのでは、偶人と変わらないな。","ENG":"You’re repeating the same phrase again and again, like a doll."},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"연합을 배신한 대가가 저승길에도 오르지 못한 채 사념이 되는 것이라니, 딱하군.","JPN":"連合を裏切った代償であの世に逝けずに邪念となるとは、気の毒だな。","ENG":"You betrayed the Alliance, and now only your will is wandering this world. I pity you.","TWN":"背叛聯盟的代價，竟然是無法安息，只能成為思念嗎？真可憐。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"후훗, 저를 동정하시다니 황송하군요.","JPN":"ふふっ、私に同情していただくとは恐縮でございます。","ENG":"Hah hah, I appreciate thy sentiment.","TWN":"呵呵，竟然還同情我，真不好意思。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"졸자를 넘어선다 해도, 과연 무엇이 바뀔는지요?","JPN":"私を越えたとしても、果たして何が変わるのでしょうか？","ENG":"But even if thou beat me, what will change?","TWN":"就算越過我，究竟又能改變什麼呢？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"다음의 일이란 것은, 직접 부딪혀 보기 전까진 누구도 모를 일이다.","JPN":"先のことは、実際に起こるまで誰もわからないものだ。","ENG":"No one knows what will happen until it actually happens.","TWN":"之後的事，不去試試誰也不知道。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나나하라류 제 1사범, 나나하라 치후유.","JPN":"七原流第一師範、七原千冬。","ENG":"As the First Instructor of the Nanahara Style, I, Nanahara Chifuyu...","TWN":"七原流模範生 七原千冬。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지금부터 단 한 번의 합으로 승부를 내도록 하지.","JPN":"次の一太刀で勝負を決することとしよう。","ENG":"... will finish you with this one single attack.","TWN":"現在要一次定勝負。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};